<script setup lang="ts">import { ref } from 'vue'; import { ArrowLeft, KeyRound } from '@lucide/vue'; import { api } from '../api/client'; import AsyncButton from '../components/AsyncButton.vue'; const username=ref('admin'),password=ref(''),confirm=ref(''),message=ref(''),error=ref(''),busy=ref(false); async function submit(){if(busy.value)return;busy.value=true;error.value='';try{await api('/recovery/reset',{method:'POST',body:JSON.stringify({username:username.value,password:password.value,confirm_password:confirm.value}),headers:{'Content-Type':'application/json'}});message.value='密码已重置，可以返回登录。'}catch(e){error.value=e instanceof Error?e.message:'重置失败'}finally{busy.value=false}}</script>
<template><main class="app-backdrop grid min-h-screen place-items-center p-4"><section class="panel w-full max-w-lg p-6 sm:p-9"><RouterLink to="/login" class="mb-7 inline-flex items-center gap-2 text-sm font-bold muted"><ArrowLeft :size="17"/>返回登录</RouterLink><KeyRound class="mb-4 text-[var(--brand)]"/><p class="eyebrow">仅限本机</p><h1 class="page-title mt-2">重置管理员密码</h1><p class="muted mt-2 text-sm leading-6">为了保护外部部署，此流程只接受 localhost 直连请求。</p><form class="mt-7 space-y-4" @submit.prevent="submit"><label class="label">用户名<input v-model="username" class="field" required/></label><label class="label">新密码<input v-model="password" class="field" type="password" minlength="8" required/></label><label class="label">确认新密码<input v-model="confirm" class="field" type="password" minlength="8" required/></label><p v-if="error" role="alert" class="text-sm font-bold text-[var(--danger)]">{{ error }}</p><p v-if="message" role="status" class="text-sm font-bold text-[var(--success)]">{{ message }}</p><AsyncButton type="submit" class="btn btn-primary w-full" :loading="busy" loading-label="正在重置…">确认重置</AsyncButton></form></section></main></template>
